import json
import os
import subprocess
import sys
from pathlib import Path

HOOKS_DIR = str(Path(__file__).parent.parent.parent.parent / "hooks")
sys.path.insert(0, HOOKS_DIR)
from lib.allowlist import match_sentinel_grant_for_write, SENTINEL_GRANT_DIR

AC_UID = "ac8-e2e-bare-syntax-scoped-sentinel"
AC_TYPE = "hook"


def test_AC8():
    """
    GIVEN: userprompt-consent-allowlist.sh is invoked as a subprocess with hook JSON payload {"prompt":"/allow Write /tmp/file.json","session_id":"<sid>"} piped to stdin, with CLAUDE_TASK_ID env var set (bare syntax, no --tool flag)
    WHEN:  the hook exits
    THEN:  the sentinel file at /tmp/claude-grants/<task_id>.json EXISTS AND allowed_operations[0] has op=="Write" and target=="/tmp/file.json" (NOT a bare wildcard {op:Write}) AND match_sentinel_grant_for_write(task_id, sid, "/tmp/file.json") returns non-None AND match_sentinel_grant_for_write(task_id, sid, "/tmp/other.json") returns None
    """
    task_id = "gen-ac8-e2e-bare-syntax"
    session_id = "gen-ac8-session"
    sentinel_path = os.path.join(SENTINEL_GRANT_DIR, f"{task_id}.json")
    legacy_path = f"/tmp/claude-bash-allowlist-{session_id}.json"
    for p in (sentinel_path, legacy_path):
        if os.path.exists(p):
            os.unlink(p)
    hook = os.path.join(HOOKS_DIR, "userprompt-consent-allowlist.sh")
    payload = json.dumps({"prompt": "/allow Write /tmp/file.json", "session_id": session_id})
    env = dict(os.environ)
    env["CLAUDE_TASK_ID"] = task_id
    try:
        r = subprocess.run(["bash", hook], input=payload, capture_output=True, text=True, env=env, timeout=10)
        assert r.returncode == 0, f"Hook exited non-zero: {r.stderr}"
        assert os.path.exists(sentinel_path), f"Sentinel missing: {sentinel_path}\nstdout: {r.stdout}"
        with open(sentinel_path) as f:
            grant = json.load(f)
        entry = grant["allowed_operations"][0]
        assert entry.get("op") == "Write"
        assert entry.get("target") == "/tmp/file.json", f"Expected target=/tmp/file.json, got: {entry}"
        assert "args_contain" not in entry, f"args_contain must not be present: {entry}"
        assert match_sentinel_grant_for_write(task_id, session_id, "/tmp/file.json") is not None
        assert match_sentinel_grant_for_write(task_id, session_id, "/tmp/other.json") is None
    finally:
        for p in (sentinel_path, legacy_path):
            if os.path.exists(p):
                os.unlink(p)
